   248→            }
   249→            moveNotation += 'x';
   250→        }
   251→
   252→        // Destination
   253→        moveNotation += toNotation;
   254→
   255→        // Special moves notation
   256→        if (moveType === 'castling') {
   257→            moveNotation = to.col > from.col ? 'O-O' : 'O-O-O';
   258→        }
   259→
   260→        // Check/checkmate
   261→        if (this.gameState.status === 'checkmate') {
   262→            moveNotation += '#';
   263→        } else if (this.gameState.inCheck) {
   264→            moveNotation += '+';
   265→        }
