   361→     * Undo en passant capture
   362→     */
   363→    undoEnPassant(from, to) {
   364→        // Move pawn back
   365→        const pawn = this.board.getPieceAt(to.row, to.col);
   366→        this.board.setPieceAt(from.row, from.col, pawn);
   367→        pawn.hasMoved = false;
   368→
   369→        // Restore captured pawn (it's on a different square than the 'to' position)
   370→        const capturedRow = from.row; // The captured pawn was on the same row as where the moving pawn started
   371→        const capturedPiece = this.moveHistory[this.moveHistory.length]?.capturedPiece;
   372→
   373→        // Find the captured pawn from the last move's data
   374→        const lastMoveData = this.moveHistory.length > 0 ?
   375→            this.moveHistory[this.moveHistory.length] : null;
   376→
   377→        if (lastMoveData && lastMoveData.capturedPiece) {
   378→            this.board.setPieceAt(capturedRow, to.col, lastMoveData.capturedPiece);
   379→
   380→            // Remove from captured pieces
   381→            const capturedColor = lastMoveData.capturedPiece.color;
   382→            const capturedArray = this.capturedPieces[capturedColor];
   383→            const index = capturedArray.findIndex(p => p.type === lastMoveData.capturedPiece.type);
   384→            if (index > -1) {
   385→                capturedArray.splice(index, 1);
   386→            }
   387→        }
   388→    }
   389→
   390→    /**
   391→     * Undo pawn promotion
   392→     */
   393→    undoPromotion(from, to, originalType) {
   394→        // Demote back to pawn
   395→        const { createPiece } = require('./pieces.js');
   396→        const pawn = createPiece(this.currentTurn, PieceType.PAWN, from.row, from.col);
   397→        this.board.setPieceAt(from.row, from.col, pawn);
   398→
   399→        // Clear the promoted piece's square
   400→        this.board.setPieceAt(to.row, to.col, null);
   401→    }
   402→
   403→    /**
   404→     * Get valid moves for a piece
   405→     * @param {Object} pos - Position {row, col}
   406→     * @returns {Array} Array of valid moves
   407→     */
   408→    getValidMoves(pos) {
   409→        return Rules.getLegalMoves(this.board, pos);
   410→    }
   411→
   412→    /**
   413→     * Notify state change listeners
   414→     */
   415→    notifyStateChange() {
   416→        if (this.onStateChange) {
   417→            this.onStateChange({
   418→                currentTurn: this.currentTurn,
   419→                gameState: this.gameState,
   420→                moveHistory: this.moveHistory,
   421→                capturedPieces: this.capturedPieces
   422→            });
   423→        }
   424→    }
   425→
   426→    /**
   427→     * Export game state
   428→     * @returns {Object} Game state
   429→     */
   430→    exportState() {
   431→        return {
   432→            board: this.board.getState(),
   433→            currentTurn: this.currentTurn,
   434→            gameState: this.gameState,
   435→            moveHistory: this.moveHistory,
   436→            capturedPieces: this.capturedPieces.map(p => ({
   437→                color: p.color,
   438→                type: p.type
   439→            }))
   440→        };
   441→    }
   442→
   443→    /**
   444→     * Import game state
   445→     * @param {Object} state - Game state to import
   446→     */
   447→    importState(state) {
   448→        // Implementation for loading saved games
   449→        // This would reconstruct the board from state
   450→    }
   451→
   452→    /**
   453→     * Reset the game
   454→     */
   455→    reset() {
   456→        this.init();
   457→    }
   458→}
