/**
 * Game Engine - Main controller for the chess game
 * Manages game flow, state, and coordinates between components
 */

class GameEngine {
    constructor() {
        this.board = new Board();
        this.currentTurn = PieceColor.WHITE;
        this.gameState = { status: 'playing', winner: null, inCheck: false };
        this.moveHistory = [];
        this.capturedPieces = { white: [], black: [] };
        this.pendingPromotion = null;

        // Callbacks for UI updates
        this.onStateChange = null;
        this.onMove = null;
        this.onCapture = null;
        this.onGameOver = null;
    }

    /**
     * Initialize a new game
     */
    init() {
        this.board.initialize();
        this.currentTurn = PieceColor.WHITE;
        this.gameState = { status: 'playing', winner: null, inCheck: false };
        this.moveHistory = [];
        this.capturedPieces = { white: [], black: [] };
        this.pendingPromotion = null;

        this.notifyStateChange();
    }

    /**
     * Make a move
     * @param {Object} from - Source position {row, col}
     * @param {Object} to - Destination position {row, col}
     * @param {string} promotionPiece - Type of piece for pawn promotion
     * @returns {Object} Move result {success, captured, moveType}
     */
    makeMove(from, to, promotionPiece = PieceType.QUEEN) {
        // Validate move
        const validationResult = Rules.validateMove(this.board, from, to, this.currentTurn);

        if (!validationResult.valid) {
            return { success: false, reason: validationResult.reason };
        }

        const piece = this.board.getPieceAt(from.row, from.col);
        const captured = this.board.getPieceAt(to.row, to.col);
        const moveType = validationResult.moveType;

        // Handle pawn promotion
        if (moveType === 'promotion') {
            this.pendingPromotion = { from, to };
            return { success: true, requiresPromotion: true };
        }

        // Execute the move
        return this.executeMove(from, to, moveType, captured);
    }

    /**
     * Execute a move on the board
     * @param {Object} from - Source position
     * @param {Object} to - Destination position
     * @param {string} moveType - Type of move
     * @param {Piece} captured - Captured piece (if any)
     * @returns {Object} Move result
     */
    executeMove(from, to, moveType, captured) {
        const piece = this.board.getPieceAt(from.row, from.col);
        let actualCaptured = captured;

        // Handle special moves
        if (moveType === 'castling') {
            this.executeCastling(from, to);
        } else if (moveType === 'enpassant') {
            actualCaptured = this.executeEnPassant(from, to);
        } else {
            // Normal move
            this.board.movePiece(from, to);
        }

        // Handle pawn promotion (if specified)
        if (this.pendingPromotion && moveType === 'promotion') {
            this.executePromotion(to, this.pendingPromotion.pieceType || PieceType.QUEEN);
            this.pendingPromotion = null;
        }

        // Track captured pieces
        if (actualCaptured) {
            const capturingColor = piece.color;
            const capturedColor = actualCaptured.color;
            this.capturedPieces[capturedColor].push(actualCaptured);

            if (this.onCapture) {
                this.onCapture(actualCaptured, to);
            }
        }

        // Update move history
        this.recordMove(from, to, piece, actualCaptured, moveType);

        // Switch turns
        this.switchTurn();

        // Update game state
        this.updateGameState();

        // Notify listeners
        this.notifyStateChange();

        if (this.onMove) {
            this.onMove(from, to, piece, actualCaptured);
        }

        if (this.gameState.status !== 'playing' && this.onGameOver) {
            this.onGameOver(this.gameState);
        }

        return {
            success: true,
            captured: actualCaptured,
            moveType: moveType
        };
    }

    /**
     * Execute castling move
     * @param {Object} from - King position
     * @param {Object} to - King destination
     */
    executeCastling(from, to) {
        const isKingSide = to.col > from.col;
        const row = from.row;

        // Move king
        this.board.movePiece(from, to);

        // Move rook
        if (isKingSide) {
            this.board.movePiece({ row, col: 7 }, { row, col: 5 });
        } else {
            this.board.movePiece({ row, col: 0 }, { row, col: 3 });
        }
    }

    /**
     * Execute en passant capture
     * @param {Object} from - Pawn position
     * @param {Object} to - Destination position
     * @returns {Piece} Captured pawn
     */
    executeEnPassant(from, to) {
        const captureRow = from.row;
        const captureCol = to.col;
        const captured = this.board.getPieceAt(captureRow, captureCol);

        // Remove captured pawn
        this.board.setPieceAt(captureRow, captureCol, null);

        // Move capturing pawn
        this.board.movePiece(from, to);

        return captured;
    }

    /**
     * Execute pawn promotion
     * @param {Object} pos - Pawn position
     * @param {string} newType - Type of piece to promote to
     */
    executePromotion(pos, newType) {
        const pawn = this.board.getPieceAt(pos.row, pos.col);

        if (pawn && pawn.type === PieceType.PAWN) {
            const newPiece = createPiece(pawn.color, newType, pos.row, pos.col);
            newPiece.hasMoved = true;
            this.board.setPieceAt(pos.row, pos.col, newPiece);
        }
    }

    /**
     * Complete pawn promotion with selected piece
     * @param {string} pieceType - Type of piece to promote to
     */
    completePromotion(pieceType) {
        if (!this.pendingPromotion) {
            return;
        }

        const { from, to } = this.pendingPromotion;
        const captured = this.board.getPieceAt(to.row, to.col);

        this.executeMove(from, to, 'promotion', captured);
        this.pendingPromotion.pieceType = pieceType;
    }

    /**
     * Switch turns
     */
    switchTurn() {
        this.currentTurn = this.currentTurn === PieceColor.WHITE ?
            PieceColor.BLACK : PieceColor.WHITE;

        // Update full move number after black moves
        if (this.currentTurn === PieceColor.WHITE) {
            this.board.fullMoveNumber++;
        }
    }

    /**
     * Update game state (check, checkmate, stalemate)
     */
    updateGameState() {
        this.gameState = Rules.getGameState(this.board, this.currentTurn);
    }

    /**
     * Record move in history
     * @param {Object} from - Source position
     * @param {Object} to - Destination position
     * @param {Piece} piece - Piece moved
     * @param {Piece} captured - Captured piece
     * @param {string} moveType - Type of move
     */
    recordMove(from, to, piece, captured, moveType) {
        const fromNotation = Position.toAlgebraic(from.row, from.col);
        const toNotation = Position.toAlgebraic(to.row, to.col);

        let moveNotation = '';

        // Piece symbol
        if (piece.type !== PieceType.PAWN) {
            const symbols = {
                king: 'K', queen: 'Q', rook: 'R', bishop: 'B', knight: 'N'
            };
            moveNotation += symbols[piece.type];
        }

        // Capture
        if (captured || moveType === 'enpassant') {
            if (piece.type === PieceType.PAWN) {
                moveNotation += fromNotation[0]; // File
            }
            moveNotation += 'x';
        }

        // Destination
        moveNotation += toNotation;

        // Special moves notation
        if (moveType === 'castling') {
            moveNotation = to.col > from.col ? 'O-O' : 'O-O-O';
        }

        // Check/checkmate
        if (this.gameState.status === 'checkmate') {
            moveNotation += '#';
        } else if (this.gameState.inCheck) {
            moveNotation += '+';
        }

        this.moveHistory.push({
            notation: moveNotation,
            from: fromNotation,
            to: toNotation,
            piece: piece.type,
            color: piece.color,
            capturedPiece: captured, // Store the actual Piece object
            moveType: moveType
        });
    }

    /**
     * Undo last move
     * @returns {boolean} True if move was undone
     */
    undoMove() {
        if (this.moveHistory.length === 0) {
            return false;
        }

        const lastMove = this.moveHistory.pop();

        // Parse positions
        const from = Position.fromAlgebraic(lastMove.from);
        const to = Position.fromAlgebraic(lastMove.to);

        // Get the piece that moved
        const piece = this.board.getPieceAt(to.row, to.col);

        // Handle special moves
        if (lastMove.moveType === 'castling') {
            this.undoCastling(from, to);
        } else if (lastMove.moveType === 'enpassant') {
            this.undoEnPassant(from, to, lastMove);
        } else if (lastMove.moveType === 'promotion') {
            this.undoPromotion(from, to, lastMove.piece);
        } else {
            // Normal move: move piece back
            this.board.movePiece(to, from);
            piece.hasMoved = false; // Reset hasMoved for proper undo
        }

        // Restore captured piece if there was one
        if (lastMove.capturedPiece && lastMove.moveType !== 'enpassant') {
            this.board.setPieceAt(to.row, to.col, lastMove.capturedPiece);

            // Remove from captured pieces array
            const capturedColor = lastMove.capturedPiece.color;
            const capturedArray = this.capturedPieces[capturedColor];
            const index = capturedArray.findIndex(p => p.type === lastMove.capturedPiece.type);
            if (index > -1) {
                capturedArray.splice(index, 1);
            }
        }

        // Switch turns back
        this.switchTurn();

        // Update game state
        this.updateGameState();

        // Notify listeners
        this.notifyStateChange();

        return true;
    }

    /**
     * Undo castling move
     */
    undoCastling(from, to) {
        const isKingSide = to.col > from.col;
        const row = from.row;

        // Move king back
        const king = this.board.getPieceAt(to.row, to.col);
        this.board.setPieceAt(from.row, from.col, king);
        king.hasMoved = false;

        // Move rook back
        if (isKingSide) {
            // Kingside: rook at file F (col 5) moves back to H (col 7)
            const rook = this.board.getPieceAt(row, 5);
            this.board.setPieceAt(row, 7, rook);
            rook.hasMoved = false;
        } else {
            // Queenside: rook at file D (col 3) moves back to A (col 0)
            const rook = this.board.getPieceAt(row, 3);
            this.board.setPieceAt(row, 0, rook);
            rook.hasMoved = false;
        }
    }

    /**
     * Undo en passant capture
     */
    undoEnPassant(from, to) {
        // Move pawn back
        const pawn = this.board.getPieceAt(to.row, to.col);
        this.board.setPieceAt(from.row, from.col, pawn);
        pawn.hasMoved = false;

        // Restore captured pawn (it's on a different square than the 'to' position)
        const capturedRow = from.row; // The captured pawn was on the same row as where the moving pawn started
        const capturedPiece = this.moveHistory[this.moveHistory.length]?.capturedPiece;

        // Find the captured pawn from the last move's data
        const lastMoveData = this.moveHistory.length > 0 ?
            this.moveHistory[this.moveHistory.length] : null;

        if (lastMoveData && lastMoveData.capturedPiece) {
            this.board.setPieceAt(capturedRow, to.col, lastMoveData.capturedPiece);

            // Remove from captured pieces
            const capturedColor = lastMoveData.capturedPiece.color;
            const capturedArray = this.capturedPieces[capturedColor];
            const index = capturedArray.findIndex(p => p.type === lastMoveData.capturedPiece.type);
            if (index > -1) {
                capturedArray.splice(index, 1);
            }
        }
    }

    /**
     * Undo pawn promotion
     */
    undoPromotion(from, to, originalType) {
        // Demote back to pawn
        const { createPiece } = require('./pieces.js');
        const pawn = createPiece(this.currentTurn, PieceType.PAWN, from.row, from.col);
        this.board.setPieceAt(from.row, from.col, pawn);

        // Clear the promoted piece's square
        this.board.setPieceAt(to.row, to.col, null);
    }

    /**
     * Get valid moves for a piece
     * @param {Object} pos - Position {row, col}
     * @returns {Array} Array of valid moves
     */
    getValidMoves(pos) {
        return Rules.getLegalMoves(this.board, pos);
    }

    /**
     * Notify state change listeners
     */
    notifyStateChange() {
        if (this.onStateChange) {
            this.onStateChange({
                currentTurn: this.currentTurn,
                gameState: this.gameState,
                moveHistory: this.moveHistory,
                capturedPieces: this.capturedPieces
            });
        }
    }

    /**
     * Export game state
     * @returns {Object} Game state
     */
    exportState() {
        return {
            board: this.board.getState(),
            currentTurn: this.currentTurn,
            gameState: this.gameState,
            moveHistory: this.moveHistory,
            capturedPieces: this.capturedPieces.map(p => ({
                color: p.color,
                type: p.type
            }))
        };
    }

    /**
     * Import game state
     * @param {Object} state - Game state to import
     */
    importState(state) {
        // Implementation for loading saved games
        // This would reconstruct the board from state
    }

    /**
     * Reset the game
     */
    reset() {
        this.init();
    }
}

